:root {
  --bg-card: #1a1a2e;
  --bg-header: #16213e;
  --bg-stat: #0f3460;
  --accent: #e94560;
  --accent-soft: #ff6b6b;
  --green: #06d6a0;
  --yellow: #ffd166;
  --text-primary: #eaeaea;
  --text-muted: #8892a4;
  --av1: #7c3aed;
  --av2: #0891b2;
  --av3: #d97706;
  --milestone-done: #06d6a0;
  --milestone-active: #ffd166;
  --milestone-inactive: #2d3a55;
  --border-subtle: #2d3a55;
}

.dashboard {
  background: var(--bg-card);
  border-radius: 14px;
  width: 500px;
  overflow: hidden;
  border: 1px solid var(--border-subtle);
}

.dash-header {
  background: var(--bg-header);
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 20px;
  border-bottom: 1px solid var(--border-subtle);
}

.event-badge {
  background: var(--accent);
  color: var(--text-primary);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.5px;
  padding: 3px 8px;
  border-radius: 4px;
}

.event-title {
  font-size: 18px;
  font-weight: 700;
  color: var(--text-primary);
  margin: 0;
  flex: 1;
}

.time-left {
  font-size: 13px;
  font-weight: 600;
  color: var(--accent-soft);
}

.dash-body {
  display: flex;
  gap: 0;
  padding: 16px;
  gap: 14px;
}

.team-card {
  flex: 1;
  background: var(--bg-header);
  border-radius: 10px;
  padding: 14px;
  border: 1px solid var(--border-subtle);
}

.team-name {
  font-size: 15px;
  font-weight: 700;
  color: var(--text-primary);
  margin-bottom: 4px;
}

.team-project {
  font-size: 12px;
  color: var(--text-muted);
  margin-bottom: 14px;
}

.member-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.member {
  display: flex;
  align-items: center;
  gap: 10px;
}

.avatar {
  width: 30px;
  height: 30px;
  border-radius: 50%;
  font-size: 11px;
  font-weight: 700;
  color: var(--text-primary);
  display: flex;
  align-items: center;
  justify-content: center;
}

.av1 { background: var(--av1); }
.av2 { background: var(--av2); }
.av3 { background: var(--av3); }

.member-name {
  font-size: 13px;
  color: var(--text-primary);
}

.stats-panel {
  display: flex;
  flex-direction: column;
  gap: 8px;
  width: 110px;
}

.stat-item {
  background: var(--bg-stat);
  border-radius: 8px;
  padding: 10px 14px;
  text-align: center;
  flex: 1;
}

.stat-value {
  font-size: 20px;
  font-weight: 700;
  color: var(--green);
  line-height: 1;
  margin-bottom: 4px;
}

.stat-label {
  font-size: 11px;
  color: var(--text-muted);
  font-weight: 500;
  letter-spacing: 0.5px;
}

.milestone-row {
  display: flex;
  padding: 0 16px 16px;
  gap: 8px;
}

.milestone {
  flex: 1;
  text-align: center;
  padding: 7px 0;
  border-radius: 6px;
  font-size: 12px;
  font-weight: 600;
  background: var(--milestone-inactive);
  color: var(--text-muted);
}

.milestone.done {
  background: var(--milestone-done);
  color: var(--bg-card);
}

.milestone.active {
  background: var(--milestone-active);
  color: var(--bg-card);
}
